158	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
159	// status (or 128 + signal for abnormal termination).
160	inline auto run_qemu_handback(const std::string& qemu_binary,
161	                              const std::string& elf_path,
162	                              const hybrid_state_v1& state,
163	                              const std::string& shared_mem_path = {},
164	                              uint64_t shared_mem_size = 0) -> int
165	{
166	  const auto port = detail::pick_free_port();
167	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
168	               qemu_binary, port);
169	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
170	                                       shared_mem_path, shared_mem_size);
171	
172	  try {
173	    restore_state_via_gdbstub(port, state);
174	  } catch (...) {
175	    ::kill(pid, SIGKILL);
176	    int wstat = 0;
177	    ::waitpid(pid, &wstat, 0);
178	    throw;
179	  }
180	
181	  int wstat = 0;
182	  if (::waitpid(pid, &wstat, 0) < 0)
183	    throw std::runtime_error(std::string{"waitpid: "}
184	                             + std::strerror(errno));
185	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
186	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
187	  return -1;
188	}
